+      scores: new Float32Array(this.exports.memory.buffer.slice(sPtr, sPtr + count * 4)),
+    };
+  }
+
+  /** Free an IVF-PQ index handle. */
+  freeIvfPqIndex(handle: number): void {
+    this.exports.ivfPqFree(handle);
+  }
